const master = require('./data/tm_conversations_master.json');
const convs = master.conversations || [];
// Search by partial segments
const parts = ['jeed', 'nettoyage', 'jeednet', 'nett', 'jeedn'];
const results = [];
for (const c of convs) {
  const name = (c.name || '').toLowerCase().replace(/[^a-z0-9]/g, '');
  for (const p of parts) {
    if (name.includes(p)) {
      results.push(c.name + ' | ' + c.cid);
      break;
    }
  }
}
console.log('Results:', results.length);
results.forEach(r => console.log(r));

// Also check chat_history directory for any file with similar name
const fs = require('fs');
const chatDir = './data/chat_history';
if (fs.existsSync(chatDir)) {
  const files = fs.readdirSync(chatDir);
  console.log('Chat history files:', files.length);
  const matched = files.filter(f => {
    const lower = f.toLowerCase();
    return lower.includes('jeed') || lower.includes('nettoyage');
  });
  console.log('Chat history matches:', matched);
}
